sys_script_include.script:
var AN_ScriptScanner = Class.create();

AN_ScriptScanner.prototype = {

    scan: function(scanId) {

        var scanGR = new GlideRecord('x_1920012_apprai_0_an_scan');

        if (!scanGR.get(scanId))
            return;

        var scopeName = scanGR.app_scope.toString();

        var issueCount = 0;

        var scriptGR = new GlideRecord('sys_script_include');
        scriptGR.addQuery('sys_scope.scope', scopeName);
        scriptGR.query();

        while (scriptGR.next()) {

            var scriptText = scriptGR.script.toString();

            if (scriptText.length > 3000) {

                this.createFinding(
                    scanId,
                    'quality',
                    'high',
                    'Large Script Include',
                    'Script Include "' +
                    scriptGR.name +
                    '" exceeds recommended size.'
                );

                issueCount++;
            }

            if (
                scriptText.indexOf('//') === -1 &&
                scriptText.indexOf('/*') === -1
            ) {

                this.createFinding(
                    scanId,
                    'quality',
                    'medium',
                    'Missing Documentation',
                    'Script Include "' +
                    scriptGR.name +
                    '" has no comments.'
                );

                issueCount++;
            }
        }

        var score = Math.max(0, 100 - (issueCount * 5));

        var scorecard = new GlideRecord('x_1920012_apprai_0_an_scorecard');
        scorecard.addQuery('scan', scanId);
        scorecard.query();

        if (scorecard.next()) {
            scorecard.quality_score = score;
            scorecard.update();
        }
    },

    createFinding: function(scanId, dimension, severity, title, description) {

        var finding = new GlideRecord('x_1920012_apprai_0_an_finding');

        finding.initialize();
        finding.scan = scanId;
        finding.dimension = dimension;
        finding.severity = severity;
        finding.title = title;
        finding.description = description;
        finding.insert();
    },

    type: 'AN_ScriptScanner'
};
